/**
 * Like buildPreamble but also returns per-section char lengths so the
 * bridge can display where context tokens are going. Prefer this in
 * new code; buildPreamble is kept for callers that only want the text.
 */
export function buildPreambleWithBreakdown(
  facts: string,
  userId?: number,
  opts?: { tailOverride?: number; compressed?: string | null }
): PreambleBreakdown {
  const {
    sendFileNote,
    askNote,
    scheduleNote,
    skillUsedNote,
    goalDoneNote,
    restartNote,
    stickerNote,
    wikiQueryNote,
    skillProposeNote,
    continueNote,
    relayDelegateNote,
    specialistProxyNote,
    parallelDelegateNote,
    rtkNote,
    envBlock,
    memoryBlock,
    dailylogBlock,
    wikiBlock,
    indexBlock,
    scriptsBlock,
    userProfileBlock,
  } = buildPreambleSections(facts, userId, opts?.tailOverride, opts?.compressed);
  const text =
    sendFileNote +
    askNote +
    scheduleNote +
    skillUsedNote +
    goalDoneNote +
    restartNote +
    stickerNote +
    wikiQueryNote +
    skillProposeNote +
    continueNote +
    relayDelegateNote +
    specialistProxyNote +
    parallelDelegateNote +
    rtkNote +
    envBlock +
    userProfileBlock +
    memoryBlock +
    dailylogBlock +
    wikiBlock +
    indexBlock +
    scriptsBlock;
  // Build a Set of stripped tail facts for dedup in memory-recall.
  const tailCount = opts?.tailOverride ?? config.memoryPreambleTail;
  const tailFacts = new Set<string>();
  if (facts) {
    const lines = facts.split(/\r?\n/).filter((l) => l.trim().length > 0);
    const recent = lines.slice(-tailCount);
    for (const line of recent) {
      tailFacts.add(line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim());
    }
  }

  return {
    text,
    total: text.length,
    toolNotes:
      sendFileNote.length +
      askNote.length +
      scheduleNote.length +
      skillUsedNote.length +
      goalDoneNote.length +
      restartNote.length +
      stickerNote.length +
      wikiQueryNote.length +
      skillProposeNote.length +
      continueNote.length +
      relayDelegateNote.length +
      specialistProxyNote.length,
    envBlock: envBlock.length,
    memoryBlock: memoryBlock.length,
    dailylogBlock: dailylogBlock.length,
    wikiBlock: wikiBlock.length,
    indexBlock: indexBlock.length,
    scriptsBlock: scriptsBlock.length,
    userProfileBlock: userProfileBlock.length,
    tailFacts,
  };
}

export function buildPreamble(facts: string, userId?: number): string {
  return buildPreambleWithBreakdown(facts, userId).text;
}

/**
 * Minimal preamble for local models (Ollama). Keeps total under ~2000 tokens
 * so small models don't choke on an oversized system prompt.
 * Includes: identity, recent facts, memory tool hints.
 */
export function buildLocalPreamble(facts: string, userId?: number): PreambleBreakdown {
  const lines = facts ? facts.split(/\r?\n/).filter((l) => l.trim().length > 0) : [];
  const tail = Math.min(5, lines.length);
  const recent = lines.slice(-tail);
  const recentContent = recent.map((l) => l.trim()).join("\n");

  const toolGuide =
    "[MCP Tools — call these via tool_call]\n" +
    "• remember({ text }) — store a fact to long-term memory. Use for user preferences, decisions, lessons.\n" +
    "• list_facts({ query, tail? }) — retrieve facts. query=topic name or substring. tail caps results (default 20).\n" +
    "• forget({ query, confirm? }) — delete facts by substring match. First call previews; second call with confirm token deletes.\n" +
    "Rules: one fact per remember call; short self-contained sentences; skip trivial/transient info.\n" +
    "[End tools]\n\n";

  let text =
    "You are a helpful AI assistant. Respond in the user's language. Be concise.\n" +
    toolGuide;

  if (recentContent) {
    text += `[Recent memory — ${tail} of ${lines.length} facts]\n${recentContent}\n[End memory]\n\n`;
  }

  const tailFacts = new Set<string>();
  for (const line of recent) {
    tailFacts.add(line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim());
  }

  return {
    text,
    total: text.length,
    toolNotes: toolGuide.length,
    envBlock: 0,
    memoryBlock: recentContent.length,
    dailylogBlock: 0,
    wikiBlock: 0,
    indexBlock: 0,
    scriptsBlock: 0,
    userProfileBlock: 0,
    tailFacts,
  };
}

/**
 * Internal: builds each section of the preamble separately so
 * buildPreambleWithBreakdown can measure them. Ordering matches what
 * buildPreamble concatenates.
 */
function buildPreambleSections(
  facts: string,
  userId?: number,
  tailOverride?: number,
  compressed?: string | null,
): {
  sendFileNote: string;

// Quick smoke test for buildPreamble tail + topic index. Run:
//   node --env-file=.env scripts/check-preamble.mjs
// Reads facts-<userId>.md from MEMORY_DIR (or F:\AI\AIMemory default),
// prints the memory block length + first 40 lines so we can eyeball the
// topic index rendering. Exercises both paths of buildMemoryBlock by
// passing userId (triggers shard-backed index when facts_Topic/<uid>/
// exists, otherwise falls back to classify-on-the-fly).
//
// userId 偵測順序：env MEMORY_USER_ID → MEMORY_DIR/.user-id → glob facts-*.md
import { readFile, readdir } from "node:fs/promises";
import { existsSync, readFileSync, readdirSync } from "node:fs";
import path from "node:path";

process.env.TELEGRAM_BOT_TOKEN ||= "dummy"; // config.ts requires it

const { buildPreamble } = await import("../dist/memory.js");
const { config } = await import("../dist/config.js");
const { listTopicShards, userShardDir } = await import(
  "../dist/facts-store.js"
);

// 動態偵測 userId
function detectUserId(memoryDir) {
  // 1. env
  if (process.env.MEMORY_USER_ID) return Number(process.env.MEMORY_USER_ID);
  // 2. .user-id 檔案
  const userIdFile = path.join(memoryDir, ".user-id");
  if (existsSync(userIdFile)) {
    const content = readFileSync(userIdFile, "utf8").trim();
    if (/^\d+$/.test(content)) return Number(content);
  }
  // 3. glob facts-*.md
  const entries = readdirSync(memoryDir);
  for (const e of entries) {
    const m = e.match(/^facts-(\d+)\.md$/);
    if (m) return Number(m[1]);
  }
  throw new Error(
    `Cannot detect userId. Set MEMORY_USER_ID env or create ${userIdFile}`
  );
}

const userId = detectUserId(config.memoryDir);
const factsFile = path.join(config.memoryDir, `facts-${userId}.md`);
const raw = (await readFile(factsFile, "utf8")).trim();
const preamble = buildPreamble(raw, userId);

// Isolate just the memory-related blocks (skip the 3 tool notes).
const memStart = preamble.indexOf("[Long-term memory about this user");
const mem = memStart >= 0 ? preamble.slice(memStart) : "(no memory block)";

console.log("=== config ===");
console.log("memoryPreambleTail:", config.memoryPreambleTail);
console.log("memoryPreambleTopics:", config.memoryPreambleTopics);
console.log("facts file:", factsFile);
console.log("total facts lines:", raw.split(/\r?\n/).filter((l) => l.trim()).length);

console.log("");
console.log("=== shard directory ===");
console.log("shardDir:", userShardDir(userId));
const shards = listTopicShards(userId);
if (shards.length === 0) {
  console.log("(no shards yet — topic index will fall back to classify path)");
  console.log("run: node scripts/rebuild-topic-shards.mjs");
} else {
  for (const s of shards) console.log(`  ${path.basename(s.file)}  (${s.count})`);
}

console.log("");
console.log("preamble total bytes:", preamble.length);
console.log("memory block bytes:", mem.length);
console.log("");
console.log("=== memory block ===");
console.log(mem);

