/**
 * Char-length breakdown of the preamble by section. Useful for the
 * bridge's context-usage UI so the user can see where the tokens go
 * (tool notes / env / memory) without having to inspect the raw string.
 *
 * All counts are raw character lengths; convert to tokens via the same
 * ~chars/4 heuristic used elsewhere (`estimateTokens`).
 */
export interface PreambleBreakdown {
  /** Full preamble text (same as the string returned by buildPreamble). */
  text: string;
  /** Total chars (= text.length). Convenience so callers don't re-measure. */
  total: number;
  /** sendFileNote + askNote + scheduleNote combined. */
  toolNotes: number;
  /** Environment block (MEMORY_DIR / SKILL_DIR / AGENT_CONFIG_DIR / USER_ID). */
  envBlock: number;
  /** Long-term memory block (recent facts + topic index). 0 if no facts. */
  memoryBlock: number;
  /** Daily log block (most recent dailylog). 0 if none. */
  dailylogBlock: number;
  /** Wiki index block (page titles from wiki/index.md). 0 if no wiki. */
  wikiBlock: number;
  /** Document tree indexes listing. 0 if no indexes. */
  indexBlock: number;
  /** Available agent-developed scripts (tool-* in scripts/). 0 if none. */
  scriptsBlock: number;
  /** User profile block (structured user identity/preferences). 0 if none. */
  userProfileBlock: number;
  /** Stripped tail facts included in preamble — for dedup in memory-recall. */
  tailFacts: Set<string>;
}



/**
 * Like buildPreamble but also returns per-section char lengths so the
 * bridge can display where context tokens are going. Prefer this in
 * new code; buildPreamble is kept for callers that only want the text.
 */
export function buildPreambleWithBreakdown(
  facts: string,
  userId?: number,
  opts?: { tailOverride?: number; compressed?: string | null }
): PreambleBreakdown {
  const {
    sendFileNote,
    askNote,
    scheduleNote,
    skillUsedNote,
    goalDoneNote,
    restartNote,
    stickerNote,
    wikiQueryNote,
    skillProposeNote,
    continueNote,
    relayDelegateNote,
    specialistProxyNote,
    parallelDelegateNote,
    rtkNote,
    envBlock,
    memoryBlock,
    dailylogBlock,
    wikiBlock,
    indexBlock,
    scriptsBlock,
    userProfileBlock,
  } = buildPreambleSections(facts, userId, opts?.tailOverride, opts?.compressed);
  const text =
    sendFileNote +
    askNote +
    scheduleNote +
    skillUsedNote +
    goalDoneNote +
    restartNote +
    stickerNote +
    wikiQueryNote +
    skillProposeNote +
    continueNote +
    relayDelegateNote +
    specialistProxyNote +
    parallelDelegateNote +
    rtkNote +
    envBlock +
    userProfileBlock +
    memoryBlock +
    dailylogBlock +
    wikiBlock +
    indexBlock +
    scriptsBlock;
  // Build a Set of stripped tail facts for dedup in memory-recall.
  const tailCount = opts?.tailOverride ?? config.memoryPreambleTail;
  const tailFacts = new Set<string>();
  if (facts) {
    const lines = facts.split(/\r?\n/).filter((l) => l.trim().length > 0);
    const recent = lines.slice(-tailCount);
    for (const line of recent) {
      tailFacts.add(line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim());
    }
  }

  return {
    text,
    total: text.length,
    toolNotes:
      sendFileNote.length +
      askNote.length +
      scheduleNote.length +
      skillUsedNote.length +
      goalDoneNote.length +
      restartNote.length +
      stickerNote.length +
      wikiQueryNote.length +
      skillProposeNote.length +
      continueNote.length +
      relayDelegateNote.length +
      specialistProxyNote.length,
    envBlock: envBlock.length,
    memoryBlock: memoryBlock.length,
    dailylogBlock: dailylogBlock.length,
    wikiBlock: wikiBlock.length,
    indexBlock: indexBlock.length,
    scriptsBlock: scriptsBlock.length,
    userProfileBlock: userProfileBlock.length,
    tailFacts,
  };
}

export function buildPreamble(facts: string, userId?: number): string {
  return buildPreambleWithBreakdown(facts, userId).text;
}

/**
 * Minimal preamble for local models (Ollama). Keeps total under ~2000 tokens
 * so small models don't choke on an oversized system prompt.
 * Includes: identity, recent facts, memory tool hints.
 */
export function buildLocalPreamble(facts: string, userId?: number): PreambleBreakdown {
  const lines = facts ? facts.split(/\r?\n/).filter((l) => l.trim().length > 0) : [];
  const tail = Math.min(5, lines.length);
  const recent = lines.slice(-tail);
  const recentContent = recent.map((l) => l.trim()).join("\n");

  const toolGuide =
    "[MCP Tools — call these via tool_call]\n" +
    "• remember({ text }) — store a fact to long-term memory. Use for user preferences, decisions, lessons.\n" +
    "• list_facts({ query, tail? }) — retrieve facts. query=topic name or substring. tail caps results (default 20).\n" +
    "• forget({ query, confirm? }) — delete facts by substring match. First call previews; second call with confirm token deletes.\n" +
    "Rules: one fact per remember call; short self-contained sentences; skip trivial/transient info.\n" +
    "[End tools]\n\n";

  let text =
    "You are a helpful AI assistant. Respond in the user's language. Be concise.\n" +
    toolGuide;

  if (recentContent) {
    text += `[Recent memory — ${tail} of ${lines.length} facts]\n${recentContent}\n[End memory]\n\n`;
  }

  const tailFacts = new Set<string>();
  for (const line of recent) {
    tailFacts.add(line.replace(/^\s*-\s*\[[^\]]+\]\s*/, "").trim());
  }

  return {
    text,
    total: text.length,
    toolNotes: toolGuide.length,
    envBlock: 0,
    memoryBlock: recentContent.length,
    dailylogBlock: 0,
    wikiBlock: 0,
    indexBlock: 0,
    scriptsBlock: 0,
    userProfileBlock: 0,
    tailFacts,
  };
}

/**
 * Internal: builds each section of the preamble separately so
 * buildPreambleWithBreakdown can measure them. Ordering matches what
 * buildPreamble concatenates.
 */
function buildPreambleSections(
  facts: string,
  userId?: number,
  tailOverride?: number,
  compressed?: string | null,
): {
  sendFileNote: string;
  askNote: string;
  scheduleNote: string;
  skillUsedNote: string;
  goalDoneNote: string;
  restartNote: string;
  stickerNote: string;
  wikiQueryNote: string;
  skillProposeNote: string;
  continueNote: string;
  relayDelegateNote: string;
  specialistProxyNote: string;
  parallelDelegateNote: string;
  rtkNote: string;
