(async () => {
  const { buildPreambleWithBreakdown } = await import('./dist/memory.js');
  const { config } = await import('./dist/config.js');
  const userId = 509424983;
  const raw = readFileSync(config.memoryDir + '/facts-' + userId + '.md', 'utf8').trim();
